const html = $json.body;
const statusCode = $json.statusCode;

const startedAt = new Date($json.startTime).getTime();
const finishedAt = Date.now();
const responseTimeMs = finishedAt - startedAt;

const extract = (regex) => {
  const match = html?.match(regex);
  return match ? match[1].trim() : null;
};

const title = extract(/<title>(.*?)<\/title>/i);
const metaDescription = extract(
  /<meta\s+name=["']description["']\s+content=["'](.*?)["']/i
);
const canonical = extract(
  /<link\s+rel=["']canonical["']\s+href=["'](.*?)["']/i
);

const h1Count = (html?.match(/<h1\b/gi) || []).length;
const h2Count = (html?.match(/<h2\b/gi) || []).length;

const wordCount = html
  ? html.replace(/<[^>]*>/g, ' ').split(/\s+/).length
  : null;

return {
  url: $json.url,
  statusCode,
  responseTimeMs,
  seoAnalyzed: statusCode === 200,

  title,
  titleLength: title?.length ?? null,
  metaDescription,
  metaDescriptionLength: metaDescription?.length ?? null,

  canonical,
  h1Count,
  h2Count,
  wordCount
};

const url =$json["urls.list"] ?? null;

const statusCode = $json.statusCode;
const headers = $json.headers || {};

function getHeader(name) {
  const key = Object.keys(headers).find(
    k => k.toLowerCase() === name.toLowerCase()
  );
  return key ? headers[key] : null;
}

const contentType = getHeader('content-type');
const cacheControl = getHeader('cache-control');
const compression = getHeader('content-encoding');
const server = getHeader('server');

const hasHSTS = !!getHeader('strict-transport-security');
const hasCSP = !!getHeader('content-security-policy');
const hasXFrameOptions = !!getHeader('x-frame-options');
const hasXContentTypeOptions = !!getHeader('x-content-type-options');
const hasReferrerPolicy = !!getHeader('referrer-policy');

const usesHttps = typeof url === 'string' && url.startsWith('https://');


const responseTimeMs =
  typeof $json.startTime === 'number'
    ? Date.now() - $json.startTime
    : null;


return {
  url,
  statusCode,
  usesHttps,

  contentType,
  cacheControl,
  compression,
  server,

  hasHSTS,
  hasCSP,
  hasXFrameOptions,
  hasXContentTypeOptions,
  hasReferrerPolicy,

  responseTimeMs,
};

const url =
  $json.url ??
  $json["urls.list"] ??
  null;

const statusCode = $json.statusCode;

// classify response
let responseClass = 'unknown';
let seoMeaning = 'Unknown response';

if (statusCode >= 300 && statusCode < 400) {
  responseClass = 'redirect';
  seoMeaning = 'Redirected URL';
} else if (statusCode === 403) {
  responseClass = 'blocked';
  seoMeaning = 'Crawling forbidden (bot protection)';
} else if (statusCode === 404) {
  responseClass = 'not_found';
  seoMeaning = 'Broken or removed page';
} else if (statusCode >= 500) {
  responseClass = 'server_error';
  seoMeaning = 'Server-side instability';
}

return {
  url,
  statusCode,

  accessible: false,
  seoAnalyzed: false,

  responseClass,
  seoMeaning,

  // technical SEO placeholders
  usesHttps: typeof url === 'string' ? url.startsWith('https://') : null,
  responseTimeMs: $json.startTime
    ? Date.now() - $json.startTime
    : null
};

const url =$json["urls.list"];

if (!url) {
  return { ...$json, robotsTxtUrl: null };
}

// Extract protocol + host manually
const match = url.match(/^(https?:\/\/[^\/]+)/i);

const robotsTxtUrl = match
  ? `${match[1]}/robots.txt`
  : null;

return {
  ...$json,
  robotsTxtUrl
};

const robotsBody = $json.robotsBody ?? '';

const robotsExists = robotsBody.length > 0;

// normalize lines
const lines = robotsExists
  ? robotsBody.split('\n').map(l => l.trim())
  : [];

const disallowRules = lines
  .filter(l => /^disallow:/i.test(l))
  .map(l => l.replace(/^disallow:\s*/i, ''));

const sitemapUrls = lines
  .filter(l => /^sitemap:/i.test(l))
  .map(l => l.replace(/^sitemap:\s*/i, ''));

const robotsBlocksAll =
  disallowRules.includes('/') ||
  disallowRules.includes('/*');

return {
  ...$json,
  robotsTxtFetched: robotsExists,
  robotsDisallowCount: disallowRules.length,
  robotsBlocksAll,
  robotsSitemaps: sitemapUrls
};

