const lighthouse = $json.lighthouseResult;

if (!lighthouse) {
  return {
    ...$json,
    pagespeedDesktopAvailable: false,
    pagespeedDesktopScore: null,
    lcpDesktop: null,
    clsDesktop: null,
    inpDesktop: null
  };
}

const categories = lighthouse.categories || {};
const audits = lighthouse.audits || {};

const pagespeedDesktopScore =
  typeof categories.performance?.score === 'number'
    ? Math.round(categories.performance.score * 100)
    : null;

const lcpDesktop =
  audits['largest-contentful-paint']?.numericValue ?? null;

const clsDesktop =
  audits['cumulative-layout-shift']?.numericValue ?? null;

const inpDesktop =
  audits['interaction-to-next-paint']?.numericValue ??
  audits['total-blocking-time']?.numericValue ??
  null;

return {
  ...$json['urls.list'],
  pagespeedDesktopAvailable: true,
  pagespeedDesktopScore,
  lcpDesktop,
  clsDesktop,
  inpDesktop
};

const lighthouse = $json.lighthouseResult;

if (!lighthouse) {
  return {
    pagespeedMobileAvailable: false,
    pagespeedMobileScore: null,
    lcpMobile: null,
    clsMobile: null,
    inpMobile: null
  };
}

const categories = lighthouse.categories || {};
const audits = lighthouse.audits || {};

return {
  pagespeedMobileAvailable: true,
  pagespeedMobileScore: Math.round(categories.performance.score * 100),
  lcpMobile: audits['largest-contentful-paint']?.numericValue ?? null,
  clsMobile: audits['cumulative-layout-shift']?.numericValue ?? null,
  inpMobile:
    audits['interaction-to-next-paint']?.numericValue ??
    audits['total-blocking-time']?.numericValue ??
    null
};

const mobileScore = $json.pagespeedMobileScore;
const desktopScore = $json.pagespeedDesktopScore;

const lcpMobile = $json.lcpMobile;
const lcpDesktop = $json.lcpDesktop;

const clsMobile = $json.clsMobile;
const clsDesktop = $json.clsDesktop;

const inpMobile = $json.inpMobile;
const inpDesktop = $json.inpDesktop;

let betterOverall = null;
let comparisonReason = null;

if (mobileScore != null && desktopScore != null) {
  if (desktopScore > mobileScore) {
    betterOverall = 'desktop';
    comparisonReason = 'Higher overall PageSpeed performance score';
  } else if (mobileScore > desktopScore) {
    betterOverall = 'mobile';
    comparisonReason = 'Higher overall PageSpeed performance score';
  } else {
    betterOverall = 'equal';
    comparisonReason = 'Equal PageSpeed performance score';
  }
}

const lcpWinner =
  lcpMobile != null && lcpDesktop != null
    ? (lcpDesktop < lcpMobile ? 'desktop' : lcpMobile < lcpDesktop ? 'mobile' : 'equal')
    : null;

const clsWinner =
  clsMobile != null && clsDesktop != null
    ? (clsDesktop < clsMobile ? 'desktop' : clsMobile < clsDesktop ? 'mobile' : 'equal')
    : null;

const inpWinner =
  inpMobile != null && inpDesktop != null
    ? (inpDesktop < inpMobile ? 'desktop' : inpMobile < inpDesktop ? 'mobile' : 'equal')
    : null;

// --- OUTPUT ---
return {
  ...$json,

  betterOverall,
  comparisonReason,

  betterLCP: lcpWinner,
  betterCLS: clsWinner,
  betterINP: inpWinner,

  scoreDiff:
    mobileScore != null && desktopScore != null
      ? desktopScore - mobileScore
      : null,

  lcpDiff:
    lcpMobile != null && lcpDesktop != null
      ? lcpMobile - lcpDesktop
      : null,

  clsDiff:
    clsMobile != null && clsDesktop != null
      ? clsMobile - clsDesktop
      : null,

  inpDiff:
    inpMobile != null && inpDesktop != null
      ? inpMobile - inpDesktop
      : null
};

let score = 100;
const penalties = [];

if ($json.statusCode !== 200) {
  score -= 40;
  penalties.push('Non-200 HTTP status');
}

if (
  $json.robotsBlocksAll === true &&
  $json.statusCode === 200 &&
  $json.robotsTxtFetched === true
) {
  score -= 10;
  penalties.push('robots.txt restricts crawling for some agents');
}

const mobileScore = $json.pagespeedMobileScore;
const desktopScore = $json.pagespeedDesktopScore;

if (mobileScore != null) {
  if (mobileScore < 50) {
    score -= 15;
    penalties.push('Very low mobile PageSpeed score');
  } else if (mobileScore < 70) {
    score -= 10;
    penalties.push('Moderate mobile PageSpeed score');
  }
}

if (desktopScore != null && desktopScore < 60) {
  score -= 5;
  penalties.push('Low desktop PageSpeed score');
}

if ($json.lcpMobile != null && $json.lcpMobile > 4000) {
  score -= 5;
  penalties.push('Poor mobile LCP');
}

if ($json.clsMobile != null && $json.clsMobile > 0.25) {
  score -= 5;
  penalties.push('Poor mobile CLS');
}

if ($json.inpMobile != null && $json.inpMobile > 300) {
  score -= 5;
  penalties.push('Poor mobile INP');
}

if (!$json.title || $json.titleLength === 0) {
  score -= 5;
  penalties.push('Missing title tag');
}

if (
  !$json.metaDescriptionLength ||
  $json.metaDescriptionLength === 0
) {
  score -= 5;
  penalties.push('Missing meta description');
}

if ($json.h1Count !== 1) {
  score -= 5;
  penalties.push('Invalid H1 structure');
}
if ($json.wordCount != null && $json.wordCount < 300) {
  score -= 5;
  penalties.push('Very low content length');
}

if ($json.usesHttps === true) {
  score += 2;
}
if (Array.isArray($json.robotsSitemaps) && $json.robotsSitemaps.length > 0) {
  score += 3;
}

score = Math.max(0, Math.min(100, score));

return {
  ...$json,
  technicalSeoScore: score,
  seoGrade:
    score >= 85 ? 'Excellent' :
    score >= 70 ? 'Good' :
    score >= 50 ? 'Average' :
    'Poor',
  seoPenalties: penalties
};
